-- ======================================================================== -- Deployment SQL - Run on phpMyAdmin BEFORE uploading new files -- Database: ganiedu_nis_db -- ======================================================================== -- 1. Add modification_approved to admissions status ENUM ALTER TABLE admissions MODIFY COLUMN status ENUM('pending','under_review','accepted','waitlist','rejected','modification_requested','modification_approved') DEFAULT 'pending'; -- 2. Increase column widths to match schema (phone and email were too narrow) ALTER TABLE schools MODIFY COLUMN phone VARCHAR(100); ALTER TABLE schools MODIFY COLUMN email VARCHAR(255); -- 3. Add resume_data column for CV preview in job applications ALTER TABLE job_applications ADD COLUMN IF NOT EXISTS resume_data LONGTEXT; -- 4. Verify columns exist (informational queries - uncomment to run) -- SELECT COLUMN_NAME FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_SCHEMA = 'ganiedu_nis_db' AND TABLE_NAME = 'schools'; -- SELECT COLUMN_NAME FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_SCHEMA = 'ganiedu_nis_db' AND TABLE_NAME = 'job_applications'; -- SELECT COLUMN_NAME FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_SCHEMA = 'ganiedu_nis_db' AND TABLE_NAME = 'admissions';